#include <stdio.h>
#include <math.h>
#define PI 3.14159265358979323846
#define EPS 1e-9

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int r, R, N;
        scanf("%d %d %d", &r, &R, &N);
        double cones[N][2];
        for (int i = 0; i < N; i++) {
            scanf("%lf %lf", &cones[i][0], &cones[i][1]);
        }
        double min_dist = R - r;
        for (int i = 0; i < N; i++) {
            double dist = sqrt(cones[i][0] * cones[i][0] + cones[i][1] * cones[i][1]) - r;
            if (dist < min_dist) min_dist = dist;
        }
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                double dist = sqrt((cones[i][0] - cones[j][0]) * (cones[i][0] - cones[j][0]) + (cones[i][1] - cones[j][1]) * (cones[i][1] - cones[j][1])) / 2;
                if (dist < min_dist) min_dist = dist;
            }
        }
        printf("%.3f\n", 2 * min_dist);
    }
    return 0;
}

