import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int r = sc.nextInt();
            int R = sc.nextInt();
            int N = sc.nextInt();
            double[][] cones = new double[N][2];
            for (int i = 0; i < N; i++) {
                cones[i][0] = sc.nextDouble();
                cones[i][1] = sc.nextDouble();
            }
            double min_dist = R - r;
            for (int i = 0; i < N; i++) {
                double dist = Math.sqrt(cones[i][0] * cones[i][0] + cones[i][1] * cones[i][1]) - r;
                min_dist = Math.min(min_dist, dist);
            }
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    double dist = Math.sqrt((cones[i][0] - cones[j][0]) * (cones[i][0] - cones[j][0]) + (cones[i][1] - cones[j][1]) * (cones[i][1] - cones[j][1])) / 2;
                    min_dist = Math.min(min_dist, dist);
                }
            }
            System.out.printf("%.3f\n", 2 * min_dist);
        }
    }
}

code.JavaScript:
const lines = require('fs').readFileSync(0,'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [r, R, N] = readline().split(' ').map(Number);
    const cones = [];
    for (let j = 0; j < N; j++) {
        cones.push(readline().split(' ').map(Number));
    }
    let min_dist = R - r;
    for (let j = 0; j < N; j++) {
        const dist = Math.sqrt(cones[j][0] ** 2 + cones[j][1] ** 2) - r;
        min_dist = Math.min(min_dist, dist);
    }
    for (let j = 0; j < N; j++) {
        for (let k = j + 1; k < N; k++) {
            const dist = Math.sqrt((cones[j][0] - cones[k][0]) ** 2 + (cones[j][1] - cones[k][1]) ** 2) / 2;
            min_dist = Math.min(min_dist, dist);
        }
    }
    console.log((2 * min_dist).toFixed(3));
}

